CREATE TRIGGER IF NOT EXISTS "oauth_registration_intent_consume_invite" BEFORE UPDATE OF "consumed_at" ON "oauth_registration_intent" WHEN OLD."consumed_at" IS NULL AND NEW."consumed_at" IS NOT NULL BEGIN SELECT RAISE(ABORT, 'oauth_intent_not_authorized') WHERE NEW."authorized_at" IS NULL OR NEW."authorized_user_id" IS NULL; SELECT RAISE(ABORT, 'oauth_invite_reservation_invalid') WHERE NEW."invite_code_id" IS NOT NULL AND NOT EXISTS (SELECT 1 FROM "invite_code" WHERE "id" = NEW."invite_code_id" AND "used_by" IS NULL AND "revoked" = 0 AND "reserved_intent_id" = NEW."id"); UPDATE "invite_code" SET "used_by" = NEW."authorized_user_id", "used_at" = NEW."consumed_at", "reserved_intent_id" = NULL, "reserved_at" = NULL WHERE "id" = NEW."invite_code_id" AND "used_by" IS NULL AND "revoked" = 0 AND "reserved_intent_id" = NEW."id"; END;
